@cli.command()
@click.argument('city')
def weather(city):
    """Show current weather for a city."""
    api_key = os.environ.get('OPENWEATHER_API_KEY')
    if not api_key:
        click.echo('Error: Set OPENWEATHER_API_KEY environment variable')
        return
    resp = requests.get(
        'https://api.openweathermap.org/data/2.5/weather',
        params={'q': city, 'appid': api_key, 'units': 'metric'},
        timeout=10,
    )
    if resp.status_code != 200:
        click.echo(f'Error: {resp.status_code} — {resp.json().get("message", "unknown")}')
        return
    data = resp.json()
    click.echo(f"{data['name']}: {data['main']['temp']}°C, {data['weather'][0]['description']}")
